info.description:
📱 MOBILE APP API - COMPLETE HDFC-STYLE SECURITY EXAMPLE

━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━

🎯 COMPLETE WORKING EXAMPLE (All Steps with Responses)

━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━

STEP 1️⃣: Login
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
POST http://localhost:9000/api/v1/auth/login

Request:
{
  "email": "reader@demo-bank.com",
  "password": "reader123"
}

Response:
{
  "token": "eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9...",
  "role": "qr_reader",
  "bank_public_key_pem": "-----BEGIN PUBLIC KEY-----
MIICIjAN...",
  "encrypted_enc_key": "y1UCljhGfrC9r6H9XTmRrDAbQ6G6HO...",
  "signature": "2d8cb8ec7d16bb61f2c739d7472ccc704..."
}

💾 App stores in memory:
  - token (for API calls)
  - bank_public_key_pem (to verify signatures)
  - encrypted_enc_key (decrypt with password)
  - signature (verify before decrypting)

━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━

STEP 2️⃣: Verify Signature & Decrypt Master Key (Client-Side)
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━

Client-side JavaScript:

// 1. Verify RSA-PSS signature
const publicKey = await crypto.subtle.importKey(
  "spki",
  pemToArrayBuffer(bank_public_key_pem),
  { name: "RSA-PSS", hash: "SHA-256" },
  false,
  ["verify"]
);

const signatureValid = await crypto.subtle.verify(
  { name: "RSA-PSS", saltLength: 32 },
  publicKey,
  hexToArrayBuffer(signature),
  new TextEncoder().encode(encrypted_enc_key)
);

if (!signatureValid) throw new Error("Invalid signature!");

// 2. Derive AES key from user password
const passwordHash = await crypto.subtle.digest(
  "SHA-256",
  new TextEncoder().encode("reader123")
);

const aesKey = await crypto.subtle.importKey(
  "raw",
  passwordHash,
  { name: "AES-GCM" },
  false,
  ["decrypt"]
);

// 3. Decrypt encrypted_enc_key
const encryptedBuffer = base64urlToArrayBuffer(encrypted_enc_key);
const nonce = encryptedBuffer.slice(0, 12);
const ciphertext = encryptedBuffer.slice(12);

const decrypted = await crypto.subtle.decrypt(
  { name: "AES-GCM", iv: nonce },
  aesKey,
  ciphertext
);

const masterEncryptionKey = new TextDecoder().decode(decrypted);

💾 App stores master key in memory (NEVER to disk!)

━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━

STEP 3️⃣: User Scans Encrypted QR Code
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━

QR Code contains:
{
  "v": "2.0",
  "data": "ZT-qd7Fc6BRd-CvBT7diT37Ri0rtSc26r2oNG8I3w_Q0rLSJ..."
}

App extracts: encrypted_payload = "ZT-qd7Fc6BRd..."

━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━

STEP 4️⃣: Call Server to Get Token (Server validates JWT only)
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━

GET http://localhost:9000/api/v1/app/scan/e3112bb8-3a38-492d?client_decrypt=true
Authorization: Bearer <token>

Response:
{
  "qr_type": "encrypted",
  "raw_encrypted_payload": "ZT-qd7Fc6BRd-CvBT7diT37Ri0rtSc26r2oNG8I3w_Q...",
  "portal_url": "http://localhost:3000/verify?token=e3112bb8..."
}

━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━

STEP 5️⃣: Decrypt Payload Locally (Client-Side)
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━

// Derive per-QR AES key
const perQrKeyMaterial = masterEncryptionKey + portal_url;
const perQrKeyHash = await crypto.subtle.digest(
  "SHA-256",
  new TextEncoder().encode(perQrKeyMaterial)
);

const perQrAesKey = await crypto.subtle.importKey(
  "raw",
  perQrKeyHash,
  { name: "AES-GCM" },
  false,
  ["decrypt"]
);

// Decrypt raw_encrypted_payload
const encPayloadBuffer = base64urlToArrayBuffer(raw_encrypted_payload);
const payloadNonce = encPayloadBuffer.slice(0, 12);
const payloadCiphertext = encPayloadBuffer.slice(12);

const decryptedPayload = await crypto.subtle.decrypt(
  { name: "AES-GCM", iv: payloadNonce },
  perQrAesKey,
  payloadCiphertext
);

const verifyUrl = new TextDecoder().decode(decryptedPayload);
// Result: "http://localhost:3000/verify?token=e3112bb8..."

━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━

STEP 6️⃣: Open Document in WebView
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━

webView.loadUrl(verifyUrl);

User sees: Beautiful formatted bank statement with:
✅ Account details
✅ Balance information
✅ "HMAC-SHA256 - Bank Server Signed" badge

━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━

🔒 SECURITY FEATURES (HDFC-Style):

✅ Password never sent to server (only hash used locally)
✅ Master key encrypted with password (server can't decrypt)
✅ RSA-PSS signature prevents tampering
✅ Per-QR unique keys (can't replay attacks)
✅ Keys stored in memory only (cleared on logout)
✅ Client-side decryption (server never sees plaintext)

━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━

